import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVFormat.Predefined;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

class CSVFormatValueOfTest {

    @Test
    void testValueOf_WithValidFormatName_ReturnsExpectedFormat() {
        CSVFormat expectedFormat = CSVFormat.DEFAULT;

        try (MockedStatic<CSVFormat.Predefined> mockedPredefined = Mockito.mockStatic(CSVFormat.Predefined.class)) {
            CSVFormat.Predefined predefinedMock = Mockito.mock(CSVFormat.Predefined.class);

            mockedPredefined.when(() -> CSVFormat.Predefined.valueOf("DEFAULT")).thenReturn(predefinedMock);
            Mockito.when(predefinedMock.getFormat()).thenReturn(expectedFormat);

            CSVFormat actualFormat = CSVFormat.valueOf("DEFAULT");

            assertSame(expectedFormat, actualFormat);
            mockedPredefined.verify(() -> CSVFormat.Predefined.valueOf("DEFAULT"));
            Mockito.verify(predefinedMock).getFormat();
        }
    }

    @Test
    void testValueOf_WithAnotherValidFormatName_ReturnsExpectedFormat() {
        CSVFormat expectedFormat = CSVFormat.EXCEL;

        try (MockedStatic<CSVFormat.Predefined> mockedPredefined = Mockito.mockStatic(CSVFormat.Predefined.class)) {
            CSVFormat.Predefined predefinedMock = Mockito.mock(CSVFormat.Predefined.class);

            mockedPredefined.when(() -> CSVFormat.Predefined.valueOf("EXCEL")).thenReturn(predefinedMock);
            Mockito.when(predefinedMock.getFormat()).thenReturn(expectedFormat);

            CSVFormat actualFormat = CSVFormat.valueOf("EXCEL");

            assertSame(expectedFormat, actualFormat);
            mockedPredefined.verify(() -> CSVFormat.Predefined.valueOf("EXCEL"));
            Mockito.verify(predefinedMock).getFormat();
        }
    }

    @Test
    void testValueOf_WithNull_ThrowsNullPointerException() {
        // Assuming CSVFormat.Predefined.valueOf throws NullPointerException on null input
        try (MockedStatic<CSVFormat.Predefined> mockedPredefined = Mockito.mockStatic(CSVFormat.Predefined.class)) {
            mockedPredefined.when(() -> CSVFormat.Predefined.valueOf(null)).thenThrow(NullPointerException.class);

            assertThrows(NullPointerException.class, () -> CSVFormat.valueOf(null));
            mockedPredefined.verify(() -> CSVFormat.Predefined.valueOf(null));
        }
    }

    @Test
    void testValueOf_WithInvalidFormatName_ThrowsIllegalArgumentException() {
        // Assuming CSVFormat.Predefined.valueOf throws IllegalArgumentException on invalid input
        try (MockedStatic<CSVFormat.Predefined> mockedPredefined = Mockito.mockStatic(CSVFormat.Predefined.class)) {
            mockedPredefined.when(() -> CSVFormat.Predefined.valueOf("INVALID_FORMAT")).thenThrow(IllegalArgumentException.class);

            assertThrows(IllegalArgumentException.class, () -> CSVFormat.valueOf("INVALID_FORMAT"));
            mockedPredefined.verify(() -> CSVFormat.Predefined.valueOf("INVALID_FORMAT"));
        }
    }
}
